import pandas as pd
import json

df = pd.DataFrame(env['data_1'])
article_ids = df['article_id'].tolist()

# Let's just count the number of business articles per year in Europe.
# We can group the article_ids by year, and then query MongoDB for each year.
df['year'] = df['publication_date'].str[:4].astype(int)
year_counts = df.groupby('year').size()
print("Articles per year in Europe:")
print(year_counts)

# For each year, we can generate a query.
queries = {}
for year in range(2010, 2021):
    ids_for_year = df[df['year'] == year]['article_id'].tolist()
    print(f"Year {year}: {len(ids_for_year)} articles")

    query = [
      {
        "$match": {
          "article_id": { "$in": ids_for_year },
          "$or": [
            { "title": { "$regex": "market|business|stock|profit|oil|company|economy|trade|revenue|shares|bank|finance|economic|crude", "$options": "i" } },
            { "description": { "$regex": "market|business|stock|profit|oil|company|economy|trade|revenue|shares|bank|finance|economic|crude", "$options": "i" } }
          ]
        }
      },
      {
        "$count": "business_articles"
      }
    ]
    queries[year] = json.dumps(query)

env['queries'] = queries

