import pandas as pd
import json

df = pd.DataFrame(env['data_1'])
df['year'] = df['publication_date'].str[:4].astype(int)

# We have the count for 2010: 312.
# Let's do the same for the other years.
# We can just generate the queries and run them.
# But wait, we can just run a single query for ALL years if we group by year in MongoDB?
# No, MongoDB doesn't have the year. The year is in SQLite.
# But we can just pass all 14860 IDs to MongoDB, and get back the IDs of the business articles!
# The problem was the response size.
# If we just project the article_id, is it too large?
# 14860 IDs is not that many. Let's try to pass all 14860 IDs and project article_id.
# Wait, the previous error was "Response too large" when we didn't filter by ID.
# If we filter by the 14860 IDs, the response will be at most 14860 documents, each with just an _id and article_id.
# Let's try that!

all_ids = df['article_id'].tolist()

query = [
  {
    "$match": {
      "article_id": { "$in": all_ids },
      "$or": [
        { "title": { "$regex": "market|business|stock|profit|oil|company|economy|trade|revenue|shares|bank|finance|economic|crude", "$options": "i" } },
        { "description": { "$regex": "market|business|stock|profit|oil|company|economy|trade|revenue|shares|bank|finance|economic|crude", "$options": "i" } }
      ]
    }
  },
  {
    "$project": {
      "_id": 0,
      "article_id": 1
    }
  }
]

env['query_all'] = json.dumps(query)

